// n8n Code Node for transforming stock data

// Get the input data - handle different possible structures
let inputData;

if ($input.all()[0].json.data && Array.isArray($input.all()[0].json.data)) {
  // If data is already an array
  inputData = $input.all()[0].json.data;
} else if ($input.all()[0].json.data[0] && $input.all()[0].json.data[0].data) {
  // If data has nested data property
  inputData = $input.all()[0].json.data[0].data;
} else {
  // Try the raw input
  inputData = $input.all()[0].json;
}

// Log for debugging (remove after testing)
console.log("Input structure:", JSON.stringify(inputData).substring(0, 200));

if (!Array.isArray(inputData) || inputData.length === 0) {
  throw new Error("Could not find valid data array in input");
}

const output = {
  stock_symbol: inputData[0].meta.symbol,
  candles: {
    "4h": [],
    "1day": [],
    "1week": []
  }
};

// Process each interval type
inputData.forEach(intervalData => {
  const interval = intervalData.meta.interval;

  if (output.candles[interval]) {
    intervalData.values.forEach(candle => {
      output.candles[interval].push({
        datetime: candle.datetime,
        open: parseFloat(candle.open),
        close: parseFloat(candle.close),
        high: parseFloat(candle.high),
        low: parseFloat(candle.low),
        volume: parseInt(candle.volume)
      });
    });
  }
});

return output;
